CREATE TABLE students (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    created_at TEXT DEFAULT (datetime('now'))
);

INSERT INTO students (name, created_at) VALUES
    ('Ahmet Yilmaz', '2026-01-15 10:30:00'),
    ('Ayse Kaya', '2026-03-22 14:45:00'),
    ('Mehmet Demir', '2026-06-01 09:00:00');

-- Mevcut tarih ve zaman
SELECT datetime('now') AS current_datetime;
SELECT date('now') AS today;
SELECT time('now') AS current_time;

-- Tarihten yil, ay, gun cikarma (strftime ile)
SELECT
    created_at,
    strftime('%Y', created_at) AS year,
    strftime('%m', created_at) AS month,
    strftime('%d', created_at) AS day
FROM students;

-- Tarih farki hesaplama (gun cinsinden, julianday ile)
SELECT
    name,
    created_at,
    CAST(julianday('now') - julianday(created_at) AS INTEGER) AS days_since_registration
FROM students;

-- Tarihe gun/ay/yil ekleme
SELECT date('now', '+30 days') AS thirty_days_later;
SELECT date('now', '+1 year') AS one_year_later;

-- Tarih formatlama
SELECT strftime('%d-%m-%Y', created_at) AS formatted_date FROM students;
SELECT strftime('%Y-%m-%d %H:%M:%S', created_at) AS full_datetime FROM students;

-- Belirli bir tarihten sonra kayit olanlar
SELECT name, created_at
FROM students
WHERE created_at >= '2026-03-01';
